import React, { useState } from 'react';

const AuthPage = () => {
  const [isLogin, setIsLogin] = useState(true);

  // Renk Paletimiz
  const colors = {
    butterYellow: '#FEFAE0',
    softPink: '#F8AD9D',
    softBeige: '#FAEDCD',
    white: '#FFFFFF'
  };

  // İç İçe Stil Objeleri (CSS yerine doğrudan JS)
  const styles = {
    container: {
      backgroundColor: colors.butterYellow,
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif"
    },
    card: {
      backgroundColor: colors.white,
      width: '100%',
      maxWidth: '400px',
      padding: '40px',
      borderRadius: '40px',
      boxShadow: '0 20px 25px -5px rgba(248, 173, 157, 0.1)',
      border: `1px solid ${colors.softBeige}`,
      textAlign: 'center'
    },
    title: {
      color: colors.softPink,
      fontSize: '32px',
      fontWeight: 'bold',
      marginBottom: '10px'
    },
    input: {
      width: '100%',
      padding: '15px',
      marginBottom: '15px',
      borderRadius: '15px',
      border: `1px solid ${colors.softBeige}`,
      backgroundColor: '#fdfdfd',
      outline: 'none',
      boxSizing: 'border-box'
    },
    button: {
      width: '100%',
      padding: '15px',
      backgroundColor: colors.softPink,
      color: 'white',
      border: 'none',
      borderRadius: '15px',
      fontWeight: 'bold',
      fontSize: '16px',
      cursor: 'pointer',
      marginTop: '10px',
      transition: '0.3s'
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h1 style={styles.title}>Planly 🌸</h1>
        <p style={{ color: '#A5A5A5', marginBottom: '30px' }}>
          {isLogin ? 'Tekrar hoş geldin!' : 'Aramıza katıl!'}
        </p>

        <form onSubmit={(e) => e.preventDefault()}>
          {!isLogin && <input style={styles.input} type="text" placeholder="Ad Soyad" />}
          <input style={styles.input} type="email" placeholder="E-posta Adresi" />
          <input style={styles.input} type="password" placeholder="Şifre" />

          <button 
            style={styles.button}
            onClick={() => window.location.href = '/onboarding'}
          >
            {isLogin ? 'Giriş Yap' : 'Kayıt Ol'}
          </button>
        </form>

        <div style={{ marginTop: '20px', fontSize: '14px', color: '#A5A5A5' }}>
          {isLogin ? 'Hesabın yok mu?' : 'Zaten üye misin?'}
          <span 
            onClick={() => setIsLogin(!isLogin)}
            style={{ color: colors.softPink, fontWeight: 'bold', marginLeft: '5px', cursor: 'pointer' }}
          >
            {isLogin ? 'Üye Ol' : 'Giriş Yap'}
          </span>
        </div>
      </div>
    </div>
  );
};

// Şimdilik sadece AuthPage'i döndürüyoruz
function App() {
  return <AuthPage />;
}

export default App;
